import React from 'react';
import { useNavigate } from 'react-router-dom';
import { listings } from '../data/mockData';
import ListingCard from '../components/ListingCard';
import BottomNav from '../components/BottomNav';

export default function Home() {
  const navigate = useNavigate();
  return (
    <div>
      <div className="page">
        <div style={{background:'linear-gradient(135deg,#6C63FF,#764ba2)',borderRadius:16,padding:20,color:'white',marginBottom:16}}>
          <h2 style={{fontSize:22,marginBottom:4}}>🏠 মেসবাহ</h2>
          <p style={{opacity:0.85,marginBottom:12}}>তোমার পছন্দের মেস খোঁজো</p>
          <input className="input" placeholder="এলাকা লিখো..." style={{background:'white',color:'#333'}} onClick={() => navigate('/listings')} readOnly />
        </div>
        <div style={{display:'flex',gap:8,marginBottom:16}}>
          {['মিরপুর','ধানমন্ডি','উত্তরা','মোহাম্মদপুর'].map(a => (
            <span key={a} onClick={() => navigate('/listings')} style={{background:'white',padding:'6px 12px',borderRadius:20,fontSize:12,cursor:'pointer',boxShadow:'0 2px 6px rgba(0,0,0,0.08)'}}>{a}</span>
          ))}
        </div>
        <h3 style={{marginBottom:12,fontWeight:700}}>সাম্প্রতিক লিস্টিং</h3>
        {listings.map(l => <ListingCard key={l._id} listing={l} />)}
      </div>
      <BottomNav />
    </div>
  );
}
